  // change (i.e. the browser has committed the new layout), then write the
  // properties immediately. Cap at MAX_TICKS frames to guarantee termination.
  let rafPending = false;
  const MAX_TICKS = 60; // ~1 s at 60 fps — generous upper bound

  function writeViewportUnits() {
    const s = document.documentElement.style;
    s.setProperty('--vw', (window.innerWidth  / 100) + 'px');
    s.setProperty('--vh', (window.innerHeight / 100) + 'px');
  }

  function updateViewportUnits() {
    if (rafPending) return;
    rafPending = true;
    requestAnimationFrame(function () {
      rafPending = false;
      writeViewportUnits();
    });
  }

  function pollUntilDimensionsChange(prevW, prevH, ticks) {
    if (window.innerWidth !== prevW || window.innerHeight !== prevH || ticks >= MAX_TICKS) {
      writeViewportUnits();
    } else {
      requestAnimationFrame(function () {
        pollUntilDimensionsChange(prevW, prevH, ticks + 1);
