/* ===== CLOCK COLOR TOKENS ===== */
:root {
  --clk-bg:        #050505;                    /* page background          */
  --clk-face:      #0e0e0e;                    /* clock face fill          */
  --clk-border:    rgba(255, 255, 255, 0.04);  /* clock circle border      */
  --clk-hand:      #FF1B0E;                    /* hand colour              */
  --clk-zero-hand: #FF1B0E;                    /* hand colour at zero      */
  --clk-zero-glow: rgba(255, 27, 14, 0.65);   /* glow at zero             */
}

/* ===== LAYOUT ===== */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

body.clock {
  background: var(--clk-bg);
  min-height: 100dvh;
}

/* ===== 6×14 CLOCK GRID (7:3 aspect ratio) ===== */
/* Columns: [3 digit][3 digit][2 colon][3 digit][3 digit] */
/* --vw / --vh are set by main.js from window.innerWidth/Height on every resize,
   guaranteeing dvh/dvw values are fresh after orientation change on iOS Safari.
   The dvw/dvh fallbacks cover the no-JS case. */
.grid-14x6 {
  display: grid;
  grid-template-columns: repeat(14, 1fr);
  width: min(calc(var(--vw, 1dvw) * 90), calc(var(--vh, 1dvh) * 90 * (14/6)), 900px);
  aspect-ratio: 14 / 6;
}

@media (min-width: 540px) {
  .grid-14x6 {
    width: min(calc(var(--vw, 1dvw) * 75), calc(var(--vh, 1dvh) * 90 * (14/6)), 900px);
  }
}

/* Landscape small screens (e.g. iPhone in landscape) */
@media screen and (orientation: landscape) and (max-height: 500px) {
  .grid-14x6 {
    width: min(calc(var(--vw, 1dvw) * 95), calc(var(--vh, 1dvh) * 85 * (14/6)), 900px);
  }
}

/* ===== MINI CLOCK CELL ===== */
.mc {
  aspect-ratio: 1;
  /* Scope layout/style/paint to each cell — prevents a style write on any
     hand from triggering recalculation across the whole document */
  contain: layout style paint;
  position: relative;
}

/* Clock face circle */
.mc::before {
  content: '';
  position: absolute;
  inset: 4%;
  border-radius: 50%;
  background: var(--clk-face);
  border: 1px solid var(--clk-border);
}

/* ===== CLOCK HANDS ===== */
/* Each hand = half-diameter: pivots from centre, extends to near-edge.
   Two hands per clock. When same angle → overlap = one half-line.
   When 180° apart → full diameter line. When 90° apart → corner ┘┌ etc. */
.hand {
  position: absolute;
  bottom: 50%;          /* pivot at clock centre */
  left: 50%;
  width: 7%;            /* thin line */
  height: 46%;          /* half-diameter: centre to near-edge */
  margin-left: -3.5%;
  background: var(--clk-hand);
  border-radius: 1px;
  transform-origin: bottom center;
  /* Promote each hand to its own compositor layer so JS-driven rotate()
     updates are applied by the GPU thread, not the main thread */
  will-change: transform;
  z-index: 2;
}

/* ===== COUNTDOWN ZERO — hands pulse red ("danger time") ===== */
@keyframes danger-pulse {
  0%, 100% {
    background: var(--clk-zero-hand);
    box-shadow:
      0 0 6px  var(--clk-zero-glow),
      0 0 20px var(--clk-zero-glow),
      0 0 40px rgba(255, 27, 14, 0.35);
  }
  50% {
    background: #ff5c50;
    box-shadow:
      0 0 10px var(--clk-zero-glow),
      0 0 40px var(--clk-zero-glow),
      0 0 80px rgba(255, 27, 14, 0.45),
      0 0 130px rgba(255, 27, 14, 0.2);
  }
}

/* Screen-level ambient glow on countdown zero */
@keyframes body-pulse {
  0%, 100% { opacity: 0.5; }
  50%       { opacity: 1;   }
}

body.countdown-zero .hand {
  animation: danger-pulse 1.2s ease-in-out infinite;
}

body.countdown-zero::after {
  content: '';
  position: fixed;
  inset: 0;
  background: radial-gradient(ellipse at center,
    transparent 35%,
    rgba(255, 27, 14, 0.14) 75%,
    rgba(255, 27, 14, 0.26) 100%
  );
  pointer-events: none;
  animation: body-pulse 1.2s ease-in-out infinite;
  z-index: 999;
}

/* ===== PAGE LOADER ===== */
.loader {
  align-items: center;
  background: var(--clk-bg);
  display: flex;
  inset: 0;
  justify-content: center;
  opacity: 1;
  pointer-events: none;
  position: fixed;
  transition: opacity 0.5s ease;
  z-index: 2000;
}

.loader.is-hidden {
  opacity: 0;
}

/* Loader clock face — sized larger than grid cells for visibility */
.loader-clock {
  width: min(18vw, 18vh, 96px);
}

/* Hours hand: one slow revolution */
.loader-clock .hand:first-child {
  animation: loader-spin 6s linear infinite;
}

/* Minutes hand: one fast revolution */
.loader-clock .hand:last-child {
  animation: loader-spin 1s linear infinite;
}

@keyframes loader-spin {
  to { transform: rotate(360deg); }
}

@media (prefers-reduced-motion: reduce) {
  .loader-clock .hand {
    animation-duration: 8s;
  }
}

