/* ===== 6×14 CLOCK GRID (7:3 aspect ratio) ===== */
/* Columns: [3 digit][3 digit][2 colon][3 digit][3 digit] */
/* svw/svh (small viewport units) are used instead of dvw/dvh to avoid
   jitter as the iOS address bar shows/hides, and instead of JS-set
   --vw/--vh custom properties which relied on the resize event — which
   iOS Safari fires late (or not at all) after orientation change.
   svw/svh are stable and update immediately on orientation change. */
.grid-14x6 {
  aspect-ratio: 14 / 6;
  display: grid;
  grid-template-columns: repeat(14, 1fr);
  width: min(90svw, calc(90svh * (14/6)), 900px);
}

@media (min-width: 540px) {
  .grid-14x6 {
    width: min(75svw, calc(90svh * (14/6)), 900px);
  }
}

/* Landscape small screens (e.g. iPhone in landscape) */
@media screen and (orientation: landscape) and (max-height: 500px) {
  .grid-14x6 {
    width: min(95svw, calc(85svh * (14/6)), 900px);
  }
}

